import React, { useState, useEffect } from "react";
import { api } from "../api"; // your axios instance
import Header from "../components/Header"; // reuse your Header

export default function Portfolio() {
  const [portfolioItems, setPortfolioItems] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    async function fetchPortfolio() {
      try {
        const token = localStorage.getItem("token");
        const response = await api.get("/portfolio", {
          headers: { Authorization: `Bearer ${token}` },
        });
        setPortfolioItems(response.data.portfolioItems);
        setError(null);
      } catch (err) {
        setError("Failed to load portfolio data.");
        console.error(err);
      } finally {
        setLoading(false);
      }
    }

    fetchPortfolio();
  }, []);

  if (loading) return <div>Loading portfolio...</div>;
  if (error) return <div style={{ color: "red" }}>{error}</div>;

  return (
    <>
      <Header />
      <div style={{ maxWidth: 600, margin: "auto", padding: 20 }}>
        <h2>My Portfolio</h2>
        {portfolioItems.length === 0 ? (
          <div>No portfolio items found.</div>
        ) : (
          <ul>
            {portfolioItems.map((item) => (
              <li key={item._id} style={{ marginBottom: 15 }}>
                <div>
                  <strong>{item.name}</strong>
                </div>
                <div>Amount: ₹{item.amount}</div>
                <div>Interest: {item.interestRate}%</div>
                <div>Date: {new Date(item.date).toLocaleDateString()}</div>
              </li>
            ))}
          </ul>
        )}
      </div>
    </>
  );
}
